const dataLayer = require('copyFromDataLayer');
let ecom = dataLayer('ecommerce', 1);

if(ecom) {
  switch(data.ecomParam) {
    case 'item_list_id':
      ecom = ecom.item_list_id;
       break;
    case 'item_list_name':
      ecom = ecom.item_list_name;
    break;
    case 'creative_name':
      ecom = ecom.creative_name;
      break;
    case 'creative_slot':
      ecom = ecom.creative_slot;
      break;
    case 'promotion_id':
      ecom = ecom.promotion_id;
      break;
    case 'promotion_name':
      ecom = ecom.promotion_name;
      break;
    case 'location_id':
      ecom = ecom.location_id;
      break;
    case 'payment_type':
      ecom = ecom.payment_type;
      break;
    case 'shipping_tier':
      ecom = ecom.shipping_tier;
      break;
    case 'transaction_id':
      ecom = ecom.transaction_id;
      break;
    case 'affiliation':
      ecom = ecom.affiliation;
      break;
    case 'coupon':
      ecom = ecom.coupon;
      break;
    case 'value':
      ecom = ecom.value;
      break;
    case 'shipping':
      ecom = ecom.shipping;
      break;
    case 'tax':
      ecom = ecom.tax;
      break;
    default:
      ecom = ecom.items;
    }
      if(data.removeNullfromItems && ecom) {
        ecom.forEach(function(object){
          for(let key in object) {
            if(object[key] === null || object[key] === '')
              object[key] = undefined;
            }
      });
  }
  return ecom;
}
return undefined;


